import { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { getApiBase } from '../utils/platform';
import usePageTitle from '../hooks/usePageTitle';
import s from './AIAssistantPage.module.css';

const MAX_HISTORY = 100;

function authHeaders() {
  const token = localStorage.getItem('aura_token');
  return token ? { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' } : { 'Content-Type': 'application/json' };
}

// -- Suggested prompts --
const SUGGESTED_PROMPTS = [
  { icon: '\u26A1', text: 'What signals are firing right now?' },
  { icon: '\uD83D\uDCC8', text: "Show my P&L today" },
  { icon: '\uD83E\uDDE0', text: 'Explain the Breakout strategy' },
  { icon: '\uD83C\uDF10', text: "What's the market regime?" },
  { icon: '\uD83D\uDD0D', text: 'Analyze AAPL' },
  { icon: '\uD83C\uDFC6', text: 'Which strategy is performing best?' },
];

// -- Quick action definitions --
const QUICK_ACTIONS = [
  { key: 'explain', label: 'Explain', icon: '\uD83D\uDCD6', placeholder: 'e.g. RSI divergence, mean reversion, Breakout strategy' },
  { key: 'analyze', label: 'Analyze', icon: '\uD83D\uDD2C', placeholder: 'e.g. AAPL, my TSLA position, momentum strategy' },
  { key: 'whatif', label: 'What-If', icon: '\uD83E\uDDEA', placeholder: 'e.g. What if I had used 2x leverage on Breakout?' },
];

// -- Source labels --
const SOURCE_LABELS = {
  positions: 'Positions',
  signals: 'Signals',
  strategies: 'Strategies',
  market_regime: 'Market Regime',
  portfolio_brain: 'Portfolio Brain',
  backtests: 'Backtests',
  risk: 'Risk',
};

// -- Simple markdown renderer --
function renderContent(text) {
  if (!text) return null;
  const lines = text.split('\n');
  return lines.map((line, li) => {
    const parts = line.split(/(\*\*[^*]+\*\*)/g);
    const rendered = parts.map((part, pi) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <strong key={pi}>{part.slice(2, -2)}</strong>;
      }
      return <span key={pi}>{part}</span>;
    });
    return (
      <span key={li}>
        {rendered}
        {li < lines.length - 1 && <br />}
      </span>
    );
  });
}

// -- Message Bubble --
function MessageBubble({ role, content, sources, tokens, latency, actionType }) {
  const isUser = role === 'user';
  return (
    <div className={isUser ? s.msgRowUser : s.msgRowAI}>
      {!isUser && (
        <div className={s.msgAvatarAI} title="Aura AI">{'\u2728'}</div>
      )}
      <div>
        {actionType && !isUser && (
          <div className={s.actionLabel}>
            {actionType === 'explain' && '\uD83D\uDCD6 Explanation'}
            {actionType === 'analyze' && '\uD83D\uDD2C Analysis'}
            {actionType === 'whatif' && '\uD83E\uDDEA What-If Scenario'}
          </div>
        )}
        <div className={isUser ? s.msgBubbleUser : s.msgBubbleAI}>
          {renderContent(content)}
        </div>
        {!isUser && (
          <>
            {sources && sources.length > 0 && (
              <div className={s.sourcesTags}>
                {sources.map(src => (
                  <span key={src} className={s.sourceTag}>
                    {SOURCE_LABELS[src] || src}
                  </span>
                ))}
              </div>
            )}
            {(tokens > 0 || latency > 0) && (
              <div className={s.msgMeta}>
                {tokens > 0 && <span className={s.msgMetaText}>{tokens.toLocaleString()} tokens</span>}
                {latency > 0 && <span className={s.msgMetaText}>{(latency / 1000).toFixed(1)}s</span>}
              </div>
            )}
          </>
        )}
      </div>
      {isUser && (
        <div className={s.msgAvatarUser} title="You">{'\uD83D\uDC64'}</div>
      )}
    </div>
  );
}

// -- Typing Indicator --
function TypingIndicator() {
  return (
    <div className={s.typingRow}>
      <div className={s.msgAvatarAI}>{'\u2728'}</div>
      <div className={s.typingBubble}>
        <div className={s.typingDot} />
        <div className={s.typingDot} />
        <div className={s.typingDot} />
      </div>
    </div>
  );
}

// -- Conversation Sidebar Item --
function ConversationItem({ conv, isActive, onSelect, onDelete }) {
  const title = conv.title || conv.id?.slice(0, 8) || 'Untitled';
  const date = conv.updated_at || conv.created_at;
  const timeStr = date ? new Date(date).toLocaleDateString(undefined, { month: 'short', day: 'numeric' }) : '';

  return (
    <div
      className={isActive ? s.convItemActive : s.convItem}
      onClick={() => onSelect(conv.id)}
    >
      <div className={s.convItemContent}>
        <div className={s.convItemTitle}>{title}</div>
        {timeStr && <div className={s.convItemDate}>{timeStr}</div>}
      </div>
      <button
        className={s.convDeleteBtn}
        onClick={(e) => { e.stopPropagation(); onDelete(conv.id); }}
        title="Delete conversation"
      >
        x
      </button>
    </div>
  );
}

// -- AI Status Badge --
function AIStatusBadge({ status }) {
  if (!status) return null;
  const isOnline = status.status === 'online' || status.healthy === true;
  const label = status.model || (isOnline ? 'AI Online' : 'AI Offline');
  return (
    <span className={isOnline ? s.statusBadgeOnline : s.statusBadgeOffline}>
      <span className={isOnline ? s.statusDotOnline : s.statusDotOffline} />
      {label}
    </span>
  );
}

// ====================================================================
export default function AIAssistantPage() {
  usePageTitle('AI Assistant');

  const navigate = useNavigate();
  const base = getApiBase();

  // -- State --
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [sending, setSending] = useState(false);
  const [rateInfo, setRateInfo] = useState(null);
  const [aiStatus, setAiStatus] = useState(null);
  const [digest, setDigest] = useState(null);
  const [showDigest, setShowDigest] = useState(false);

  // Conversations
  const [conversations, setConversations] = useState([]);
  const [activeConvId, setActiveConvId] = useState(null);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [loadingConvs, setLoadingConvs] = useState(false);

  // Quick action mode
  const [quickAction, setQuickAction] = useState(null); // null | 'explain' | 'analyze' | 'whatif'

  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);

  // -- Scroll to bottom --
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, sending]);

  // -- Fetch AI status, rate limit, digest, conversations on mount --
  useEffect(() => {
    const headers = authHeaders();

    fetch(`${base}/assistant/status`, { headers })
      .then(r => r.ok ? r.json() : null)
      .then(data => { if (data) setAiStatus(data); })
      .catch(() => {});

    fetch(`${base}/ai/rate-limit`, { headers })
      .then(r => r.ok ? r.json() : null)
      .then(data => { if (data) setRateInfo(data); })
      .catch(() => {});

    fetch(`${base}/ai/digest`, { headers })
      .then(r => r.ok ? r.json() : null)
      .then(data => { if (data) setDigest(data); })
      .catch(() => {});

    loadConversations();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // -- Load conversations list --
  const loadConversations = useCallback(async () => {
    setLoadingConvs(true);
    try {
      const resp = await fetch(`${base}/assistant/conversations`, { headers: authHeaders() });
      if (resp.ok) {
        const data = await resp.json();
        setConversations(Array.isArray(data) ? data : (data.conversations || []));
      }
    } catch { /* ignore */ }
    setLoadingConvs(false);
  }, [base]);

  // -- Load a specific conversation --
  const loadConversation = useCallback(async (convId) => {
    try {
      const resp = await fetch(`${base}/assistant/conversations/${convId}`, { headers: authHeaders() });
      if (resp.ok) {
        const data = await resp.json();
        const msgs = data.messages || [];
        setMessages(msgs.slice(-MAX_HISTORY));
        setActiveConvId(convId);
      }
    } catch { /* ignore */ }
  }, [base]);

  // -- Delete a conversation --
  const deleteConversation = useCallback(async (convId) => {
    try {
      await fetch(`${base}/assistant/conversations/${convId}`, {
        method: 'DELETE',
        headers: authHeaders(),
      });
      setConversations(prev => prev.filter(c => c.id !== convId));
      if (activeConvId === convId) {
        setActiveConvId(null);
        setMessages([]);
      }
    } catch { /* ignore */ }
  }, [base, activeConvId]);

  // -- New conversation --
  const handleNewConversation = useCallback(() => {
    setActiveConvId(null);
    setMessages([]);
    setQuickAction(null);
    inputRef.current?.focus();
  }, []);

  // -- Send chat message --
  const handleSend = useCallback(async (overrideText) => {
    const text = (overrideText || input).trim();
    if (!text || sending) return;

    setInput('');
    const userMsg = { role: 'user', content: text, ts: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setSending(true);

    // Determine endpoint and body based on quickAction
    let endpoint = `${base}/assistant/chat`;
    let body = { message: text };
    let actionType = null;

    if (quickAction === 'explain') {
      endpoint = `${base}/assistant/explain`;
      body = { topic: text };
      actionType = 'explain';
    } else if (quickAction === 'analyze') {
      endpoint = `${base}/assistant/analyze`;
      body = { target: text };
      actionType = 'analyze';
    } else if (quickAction === 'whatif') {
      endpoint = `${base}/assistant/backtest-whatif`;
      body = { scenario: text };
      actionType = 'whatif';
    }

    // Include conversation_id if we have one
    if (activeConvId) {
      body.conversation_id = activeConvId;
    }

    try {
      const resp = await fetch(endpoint, {
        method: 'POST',
        headers: authHeaders(),
        body: JSON.stringify(body),
      });

      if (resp.status === 429) {
        const aiMsg = {
          role: 'assistant',
          content: 'You\'ve reached your daily AI query limit. Upgrade to Pro for unlimited access to the AI Trading Assistant.',
          ts: Date.now(),
          sources: [],
        };
        setMessages(prev => [...prev, aiMsg]);
        setRateInfo(prev => prev ? { ...prev, remaining: 0, allowed: false } : prev);
        return;
      }

      if (!resp.ok) {
        throw new Error(`HTTP ${resp.status}`);
      }

      const data = await resp.json();
      const aiMsg = {
        role: 'assistant',
        content: data.message || data.response || data.explanation || data.analysis || data.result || 'No response received.',
        ts: Date.now(),
        sources: data.context_sources || data.sources || [],
        tokens: data.tokens_used || 0,
        latency: data.latency_ms || 0,
        actionType,
      };
      setMessages(prev => [...prev, aiMsg]);

      // Track conversation id from response
      if (data.conversation_id && !activeConvId) {
        setActiveConvId(data.conversation_id);
      }

      // Update remaining queries
      if (data.remaining_today !== null && data.remaining_today !== undefined) {
        setRateInfo(prev => prev ? { ...prev, remaining: data.remaining_today } : prev);
      }

      // Refresh conversation list
      loadConversations();
    } catch (err) {
      const aiMsg = {
        role: 'assistant',
        content: `Sorry, I couldn't process that request. ${err.message || 'Please try again.'}`,
        ts: Date.now(),
        sources: [],
      };
      setMessages(prev => [...prev, aiMsg]);
    } finally {
      setSending(false);
      setQuickAction(null);
      inputRef.current?.focus();
    }
  }, [input, sending, quickAction, activeConvId, base, loadConversations]);

  // -- Key handler --
  const handleKeyDown = useCallback((e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
    if (e.key === 'Escape' && quickAction) {
      setQuickAction(null);
    }
  }, [handleSend, quickAction]);

  // -- Clear current chat --
  const handleClear = useCallback(() => {
    setMessages([]);
    setActiveConvId(null);
    setQuickAction(null);
  }, []);

  // Rate limit display
  const isLimited = rateInfo && !rateInfo.is_unlimited && rateInfo.remaining !== null;
  const isBlocked = rateInfo && rateInfo.allowed === false;

  // Active quick action config
  const activeAction = QUICK_ACTIONS.find(a => a.key === quickAction);

  // Placeholder text
  const getPlaceholder = () => {
    if (isBlocked) return 'Daily limit reached -- upgrade for unlimited access';
    if (activeAction) return activeAction.placeholder;
    return 'Ask about positions, strategies, signals, market regime...';
  };

  return (
    <div className={s.pageLayout}>
      {/* -- Conversation Sidebar -- */}
      {sidebarOpen && (
        <div className={s.sidebar}>
          <div className={s.sidebarHeader}>
            <span className={s.sidebarTitle}>Conversations</span>
            <button className={s.newConvBtn} onClick={handleNewConversation} title="New conversation">+</button>
          </div>
          <div className={s.sidebarList}>
            {loadingConvs && conversations.length === 0 && (
              <div className={s.sidebarEmpty}>Loading...</div>
            )}
            {!loadingConvs && conversations.length === 0 && (
              <div className={s.sidebarEmpty}>No conversations yet</div>
            )}
            {conversations.map(conv => (
              <ConversationItem
                key={conv.id}
                conv={conv}
                isActive={conv.id === activeConvId}
                onSelect={loadConversation}
                onDelete={deleteConversation}
              />
            ))}
          </div>
          {/* Digest section */}
          {digest && (
            <div className={s.digestSection}>
              <button
                className={s.digestToggle}
                onClick={() => setShowDigest(prev => !prev)}
              >
                Daily Digest {showDigest ? '\u25B2' : '\u25BC'}
              </button>
              {showDigest && (
                <div className={s.digestContent}>
                  {digest.summary || digest.digest || 'No digest available today.'}
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {/* -- Main Chat Area -- */}
      <div className={s.page}>
        {/* -- Header -- */}
        <div className={s.header}>
          <div className={s.headerLeft}>
            <button
              className={s.sidebarToggle}
              onClick={() => setSidebarOpen(prev => !prev)}
              title={sidebarOpen ? 'Hide sidebar' : 'Show sidebar'}
            >
              {sidebarOpen ? '\u2630' : '\u2630'}
            </button>
            <span className={s.sparkleIcon}>{'\u2728'}</span>
            <div className={s.titleBlock}>
              <h1>AI Trading Assistant</h1>
              <p>Powered by Gemini Flash with live portfolio context</p>
            </div>
          </div>
          <div className={s.headerRight}>
            <AIStatusBadge status={aiStatus} />
            {isLimited && (
              <span className={rateInfo.remaining <= 1 ? s.rateBadgeWarn : s.rateBadge}>
                {rateInfo.remaining}/{rateInfo.daily_limit} queries
              </span>
            )}
            {rateInfo?.is_unlimited && (
              <span className={s.rateBadge}>Unlimited</span>
            )}
            {messages.length > 0 && (
              <button className={s.clearBtn} onClick={handleClear}>Clear</button>
            )}
          </div>
        </div>

        {/* -- Quick Actions Bar -- */}
        <div className={s.quickActionsBar}>
          {QUICK_ACTIONS.map(action => (
            <button
              key={action.key}
              className={quickAction === action.key ? s.quickActionBtnActive : s.quickActionBtn}
              onClick={() => setQuickAction(prev => prev === action.key ? null : action.key)}
              disabled={sending || isBlocked}
            >
              <span className={s.quickActionIcon}>{action.icon}</span>
              {action.label}
            </button>
          ))}
          {quickAction && (
            <span className={s.quickActionHint}>
              {activeAction?.label} mode -- press Esc to cancel
            </span>
          )}
        </div>

        {/* -- Messages / Welcome -- */}
        <div className={s.messagesArea}>
          {messages.length === 0 && !sending ? (
            <div className={s.welcome}>
              <div className={s.welcomeIcon}>{'\u2728'}</div>
              <h2 className={s.welcomeTitle}>Ask me anything about your portfolio</h2>
              <p className={s.welcomeDesc}>
                I have real-time access to your positions, trading signals, 83 strategies,
                market regime data, and cross-bot intelligence from Alpha, Beta, and Crypto agents.
              </p>
              <div className={s.suggestedGrid}>
                {SUGGESTED_PROMPTS.map((prompt, i) => (
                  <button
                    key={i}
                    className={s.suggestBtn}
                    onClick={() => handleSend(prompt.text)}
                    disabled={sending || isBlocked}
                  >
                    <span className={s.suggestIcon}>{prompt.icon}</span>
                    {prompt.text}
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <>
              {messages.map((msg, i) => (
                <MessageBubble
                  key={`${msg.ts}-${i}`}
                  role={msg.role}
                  content={msg.content}
                  sources={msg.sources}
                  tokens={msg.tokens}
                  latency={msg.latency}
                  actionType={msg.actionType}
                />
              ))}
              {sending && <TypingIndicator />}
            </>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* -- Premium Gate (if blocked) -- */}
        {isBlocked && (
          <div className={s.premiumGate}>
            <div className={s.premiumIcon}>{'\uD83D\uDD12'}</div>
            <h2 className={s.premiumTitle}>Daily Limit Reached</h2>
            <p className={s.premiumDesc}>
              Free tier includes 5 AI queries per day. Upgrade to Pro or Elite for unlimited
              AI Trading Assistant access.
            </p>
            <button className={s.upgradeBtn} onClick={() => navigate('/pricing')}>
              Upgrade to Pro
            </button>
          </div>
        )}

        {/* -- Input Bar -- */}
        <div className={s.inputBar}>
          <div className={s.inputWrap}>
            {quickAction && (
              <span className={s.inputActionTag}>
                {activeAction?.icon} {activeAction?.label}
              </span>
            )}
            <input
              ref={inputRef}
              className={s.inputField}
              type="text"
              placeholder={getPlaceholder()}
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              disabled={sending || isBlocked}
              autoFocus
            />
          </div>
          <button
            className={s.sendBtn}
            onClick={() => handleSend()}
            disabled={!input.trim() || sending || isBlocked}
            title="Send (Enter)"
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M22 2L11 13" />
              <path d="M22 2L15 22L11 13L2 9L22 2Z" />
            </svg>
          </button>
        </div>

        <div className={s.disclaimer}>
          This is informational only -- not financial advice. AI responses may contain errors.
        </div>
      </div>
    </div>
  );
}
